	@Test
	void slotComparisonCompilesToOrderedIdFilter() {
		NativeBooleanFilter filter = compiler
				.compileBoolean(new Compare(new Var("a"), new Var("b"), Compare.CompareOp.LT));

		assertThat(filter.getClass().getSimpleName()).isEqualTo("OrderedSlotCompareFilter");
	}

	@Test
	void slotComparisonDecidesResourceInequalityOnRawIds() {
		// Theme cluster-E regression shape (FILTER(?optCopy != ?member)): two bound resource slots must
		// decide EQ/NE on their canonical ids instead of materializing both values through the generic
		// fallback on every row.
		NativeBooleanFilter filter = compiler
				.compileBoolean(new Compare(new Var("a"), new Var("b"), Compare.CompareOp.NE));
		assertThat(filter.getClass().getSimpleName()).isEqualTo("OrderedSlotCompareFilter");

		long first = ValueIds.createId(ValueIds.T_URI, 11L);
		long second = ValueIds.createId(ValueIds.T_URI, 12L);

		assertThat(filter.accept(rowWith(first, second)))
				.as("distinct resource ids must decide != natively, not through the generic fallback")
				.isTrue();
		assertThat(filter.accept(rowWith(first, first)))
				.as("identical resource ids must decide != natively as false")
				.isFalse();
	}

	@Test
	void slotComparisonDecidesResourceEqualityOnRawIds() {
		NativeBooleanFilter filter = compiler
				.compileBoolean(new Compare(new Var("a"), new Var("b"), Compare.CompareOp.EQ));
		assertThat(filter.getClass().getSimpleName()).isEqualTo("OrderedSlotCompareFilter");

		long first = ValueIds.createId(ValueIds.T_URI, 11L);
		long second = ValueIds.createId(ValueIds.T_URI, 12L);

		assertThat(filter.accept(rowWith(first, first)))
				.as("identical resource ids must decide = natively as true")
				.isTrue();
		assertThat(filter.accept(rowWith(first, second)))
				.as("distinct resource ids must decide = natively as false")
				.isFalse();
	}

	@Test
	void slotComparisonKeepsGenericFallbackForMixedKinds() {
		// A resource id against a value-collapsible literal id must stay on the generic evaluator: raw
		// ids cannot prove value (in)equality across kinds. The mocked generic step evaluates to false.
		NativeBooleanFilter filter = compiler
				.compileBoolean(new Compare(new Var("a"), new Var("b"), Compare.CompareOp.NE));

		long resource = ValueIds.createId(ValueIds.T_URI, 11L);
		long integer = LmdbNativeValueCodec
				.packInline(LmdbNativeValueCodec.fromValue(SimpleValueFactory.getInstance().createLiteral(10)));

		assertThat(filter.accept(rowWith(resource, integer)))
				.as("mixed-kind comparisons must keep consulting the generic fallback")
				.isFalse();
	}

	private static RowState rowWith(long a, long b) {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("a", 0, "b", 1), null);
		layout.freeze(List.of("a", "b"));
		RowState row = new RowState(null, layout, EmptyBindingSet.getInstance());
		Arrays.fill(row.slots, LmdbNativeAggregateCompiler.UNKNOWN);
		row.slots[0] = a;
		row.slots[1] = b;
		row.recomputeBoundMask();
		return row;
	}

	@Test
	void constantComparisonCompilesToCachedIdFilter() {
		NativeBooleanFilter filter = compiler.compileBoolean(new Compare(new Var("a"),
				new ValueConstant(SimpleValueFactory.getInstance().createLiteral(10)), Compare.CompareOp.LT));

		assertThat(filter).isInstanceOf(CachedCompareFilter.class);
	}

	@Test
	void assuredComparisonCompilesWithoutUnknownCheck() {
		Compare compare = new Compare(new Var("a"),
				new ValueConstant(SimpleValueFactory.getInstance().createLiteral(10)), Compare.CompareOp.LT);

		CachedCompareFilter checked = (CachedCompareFilter) compiler.compileBoolean(compare, 0L);
		CachedCompareFilter assured = (CachedCompareFilter) compiler.compileBoolean(compare, 1L);

		assertThat(checked.checkBound).isTrue();
		assertThat(assured.checkBound).isFalse();
	}

	@Test
	void scalarConstantsAreDecodedOnceAtCompileTime() {
		NativeLmdbQuerySource source = mock(NativeLmdbQuerySource.class);
		LmdbNativeValueCodec codec = new LmdbNativeValueCodec(mock(ValueStore.class));
		LmdbNativeScalarExpressionCompiler scalar = new LmdbNativeScalarExpressionCompiler(source, codec, name -> -1);
		Value constant = SimpleValueFactory.getInstance().createLiteral("constant");

		for (LmdbNativeCompiledValue value : new LmdbNativeCompiledValue[] {
				scalar.compileValue(new ValueConstant(constant)),
				scalar.compileValue(new Var("constant", constant)) }) {
			LmdbNativeValueCodec.DecodedValue first = value.evaluator
					.eval(slot -> NativeLmdbQuerySource.UNKNOWN_ID);
			LmdbNativeValueCodec.DecodedValue second = value.evaluator
					.eval(slot -> NativeLmdbQuerySource.UNKNOWN_ID);

			assertThat(second).isSameAs(first);
		}
	}
